67	// Install performs an installation operation.
68	type Install struct {
69		cfg *Configuration
70	
71		ChartPathOptions
72	
73		ClientOnly      bool
74		Force           bool
75		CreateNamespace bool
76		DryRun          bool
77		DryRunOption    string
78		// HideSecret can be set to true when DryRun is enabled in order to hide
79		// Kubernetes Secrets in the output. It cannot be used outside of DryRun.
80		HideSecret               bool
81		DisableHooks             bool
82		Replace                  bool
83		Wait                     bool
84		WaitForJobs              bool
85		Devel                    bool
86		DependencyUpdate         bool
87		Timeout                  time.Duration
88		Namespace                string
89		ReleaseName              string
90		GenerateName             bool
91		NameTemplate             string
92		Description              string
93		OutputDir                string
94		Atomic                   bool
95		SkipCRDs                 bool
96		SubNotes                 bool
97		HideNotes                bool
98		SkipSchemaValidation     bool
99		DisableOpenAPIValidation bool
100		IncludeCRDs              bool
101		Labels                   map[string]string
102		// KubeVersion allows specifying a custom kubernetes version to use and
103		// APIVersions allows a manual set of supported API Versions to be passed
104		// (for things like templating). These are ignored if ClientOnly is false
105		KubeVersion *chartutil.KubeVersion
106		APIVersions chartutil.VersionSet
107		// Used by helm template to render charts with .Release.IsUpgrade. Ignored if Dry-Run is false
108		IsUpgrade bool
109		// Enable DNS lookups when rendering templates
110		EnableDNS bool
111		// Used by helm template to add the release as part of OutputDir path
112		// OutputDir/<ReleaseName>
113		UseReleaseName bool
114		// TakeOwnership will ignore the check for helm annotations and take ownership of the resources.
115		TakeOwnership bool
116		PostRenderer  postrender.PostRenderer
117		// Lock to control raceconditions when the process receives a SIGTERM
118		Lock sync.Mutex
119	}
