121	// ChartPathOptions captures common options used for controlling chart paths
122	type ChartPathOptions struct {
123		CaFile                string // --ca-file
124		CertFile              string // --cert-file
125		KeyFile               string // --key-file
126		InsecureSkipTLSverify bool   // --insecure-skip-verify
127		PlainHTTP             bool   // --plain-http
128		Keyring               string // --keyring
129		Password              string // --password
130		PassCredentialsAll    bool   // --pass-credentials
131		RepoURL               string // --repo
132		Username              string // --username
133		Verify                bool   // --verify
134		Version               string // --version
135	
136		// registryClient provides a registry client but is not added with
137		// options from a flag
138		registryClient *registry.Client
139	}
