141	// NewInstall creates a new Install object with the given configuration.
142	func NewInstall(cfg *Configuration) *Install {
143		in := &Install{
144			cfg: cfg,
145		}
146		in.ChartPathOptions.registryClient = cfg.RegistryClient
147	
148		return in
149	}
