161	func (i *Install) installCRDs(crds []chart.CRD) error {
162		// We do these one file at a time in the order they were read.
163		totalItems := []*resource.Info{}
164		for _, obj := range crds {
165			// Read in the resources
166			res, err := i.cfg.KubeClient.Build(bytes.NewBuffer(obj.File.Data), false)
167			if err != nil {
168				return errors.Wrapf(err, "failed to install CRD %s", obj.Name)
169			}
170	
171			// Send them to Kube
172			if _, err := i.cfg.KubeClient.Create(res); err != nil {
173				// If the error is CRD already exists, continue.
174				if apierrors.IsAlreadyExists(err) {
175					crdName := res[0].Name
176					i.cfg.Log("CRD %s is already present. Skipping.", crdName)
177					continue
178				}
179				return errors.Wrapf(err, "failed to install CRD %s", obj.Name)
180			}
181			totalItems = append(totalItems, res...)
182		}
183		if len(totalItems) > 0 {
184			// Give time for the CRD to be recognized.
185			if err := i.cfg.KubeClient.Wait(totalItems, 60*time.Second); err != nil {
186				return err
187			}
188	
189			// If we have already gathered the capabilities, we need to invalidate
190			// the cache so that the new CRDs are recognized. This should only be
191			// the case when an action configuration is reused for multiple actions,
192			// as otherwise it is later loaded by ourselves when getCapabilities
193			// is called later on in the installation process.
194			if i.cfg.Capabilities != nil {
195				discoveryClient, err := i.cfg.RESTClientGetter.ToDiscoveryClient()
196				if err != nil {
197					return err
198				}
199	
200				i.cfg.Log("Clearing discovery cache")
201				discoveryClient.Invalidate()
202	
203				_, _ = discoveryClient.ServerGroups()
204			}
205	
206			// Invalidate the REST mapper, since it will not have the new CRDs
207			// present.
208			restMapper, err := i.cfg.RESTClientGetter.ToRESTMapper()
209			if err != nil {
210				return err
211			}
212			if resettable, ok := restMapper.(meta.ResettableRESTMapper); ok {
213				i.cfg.Log("Clearing REST mapper cache")
214				resettable.Reset()
215			}
216		}
217		return nil
218	}
219	
220	// Run executes the installation
221	//
222	// If DryRun is set to true, this will prepare the release, but not install it
223	
224	func (i *Install) Run(chrt *chart.Chart, vals map[string]interface{}) (*release.Release, error) {
225		ctx := context.Background()
226		return i.RunWithContext(ctx, chrt, vals)
227	}
228	
229	// Run executes the installation with Context
230	//
231	// When the task is cancelled through ctx, the function returns and the install
232	// proceeds in the background.
233	func (i *Install) RunWithContext(ctx context.Context, chrt *chart.Chart, vals map[string]interface{}) (*release.Release, error) {
234		// Check reachability of cluster unless in client-only mode (e.g. `helm template` without `--validate`)
235		if !i.ClientOnly {
236			if err := i.cfg.KubeClient.IsReachable(); err != nil {
237				return nil, err
238			}
239		}
240	
241		// HideSecret must be used with dry run. Otherwise, return an error.
242		if !i.isDryRun() && i.HideSecret {
243			return nil, errors.New("Hiding Kubernetes secrets requires a dry-run mode")
244		}
245	
246		if err := i.availableName(); err != nil {
247			return nil, err
248		}
249	
250		if err := chartutil.ProcessDependenciesWithMerge(chrt, vals); err != nil {
251			return nil, err
252		}
253	
254		var interactWithRemote bool
255		if !i.isDryRun() || i.DryRunOption == "server" || i.DryRunOption == "none" || i.DryRunOption == "false" {
256			interactWithRemote = true
257		}
258	
259		// Pre-install anything in the crd/ directory. We do this before Helm
260		// contacts the upstream server and builds the capabilities object.
261		if crds := chrt.CRDObjects(); !i.ClientOnly && !i.SkipCRDs && len(crds) > 0 {
262			// On dry run, bail here
263			if i.isDryRun() {
264				i.cfg.Log("WARNING: This chart or one of its subcharts contains CRDs. Rendering may fail or contain inaccuracies.")
265			} else if err := i.installCRDs(crds); err != nil {
266				return nil, err
267			}
268		}
269	
270		if i.ClientOnly {
271			// Add mock objects in here so it doesn't use Kube API server
272			// NOTE(bacongobbler): used for `helm template`
273			i.cfg.Capabilities = chartutil.DefaultCapabilities.Copy()
274			if i.KubeVersion != nil {
275				i.cfg.Capabilities.KubeVersion = *i.KubeVersion
276			}
277			i.cfg.Capabilities.APIVersions = append(i.cfg.Capabilities.APIVersions, i.APIVersions...)
278			i.cfg.KubeClient = &kubefake.PrintingKubeClient{Out: io.Discard}
279	
280			mem := driver.NewMemory()
281			mem.SetNamespace(i.Namespace)
282			i.cfg.Releases = storage.Init(mem)
283		} else if !i.ClientOnly && len(i.APIVersions) > 0 {
284			i.cfg.Log("API Version list given outside of client only mode, this list will be ignored")
285		}
286	
287		// Make sure if Atomic is set, that wait is set as well. This makes it so
288		// the user doesn't have to specify both
289		i.Wait = i.Wait || i.Atomic
290	
291		caps, err := i.cfg.getCapabilities()
292		if err != nil {
293			return nil, err
294		}
295	
296		// special case for helm template --is-upgrade
297		isUpgrade := i.IsUpgrade && i.isDryRun()
298		options := chartutil.ReleaseOptions{
299			Name:      i.ReleaseName,
300			Namespace: i.Namespace,
301			Revision:  1,
302			IsInstall: !isUpgrade,
303			IsUpgrade: isUpgrade,
304		}
305		valuesToRender, err := chartutil.ToRenderValuesWithSchemaValidation(chrt, vals, options, caps, i.SkipSchemaValidation)
306		if err != nil {
307			return nil, err
308		}
309	
310		if driver.ContainsSystemLabels(i.Labels) {
311			return nil, fmt.Errorf("user supplied labels contains system reserved label name. System labels: %+v", driver.GetSystemLabels())
312		}
313	
314		rel := i.createRelease(chrt, vals, i.Labels)
315	
316		var manifestDoc *bytes.Buffer
317		rel.Hooks, manifestDoc, rel.Info.Notes, err = i.cfg.renderResources(chrt, valuesToRender, i.ReleaseName, i.OutputDir, i.SubNotes, i.UseReleaseName, i.IncludeCRDs, i.PostRenderer, interactWithRemote, i.EnableDNS, i.HideSecret)
318		// Even for errors, attach this if available
319		if manifestDoc != nil {
320			rel.Manifest = manifestDoc.String()
321		}
322		// Check error from render
323		if err != nil {
324			rel.SetStatus(release.StatusFailed, fmt.Sprintf("failed to render resource: %s", err.Error()))
325			// Return a release with partial data so that the client can show debugging information.
326			return rel, err
327		}
328	
329		// Mark this release as in-progress
330		rel.SetStatus(release.StatusPendingInstall, "Initial install underway")
331	
332		var toBeAdopted kube.ResourceList
333		resources, err := i.cfg.KubeClient.Build(bytes.NewBufferString(rel.Manifest), !i.DisableOpenAPIValidation)
334		if err != nil {
335			return nil, errors.Wrap(err, "unable to build kubernetes objects from release manifest")
336		}
337	
338		// It is safe to use "force" here because these are resources currently rendered by the chart.
339		err = resources.Visit(setMetadataVisitor(rel.Name, rel.Namespace, true))
340		if err != nil {
341			return nil, err
342		}
343	
344		// Install requires an extra validation step of checking that resources
345		// don't already exist before we actually create resources. If we continue
346		// forward and create the release object with resources that already exist,
347		// we'll end up in a state where we will delete those resources upon
348		// deleting the release because the manifest will be pointing at that
349		// resource
350		if !i.ClientOnly && !isUpgrade && len(resources) > 0 {
351			if i.TakeOwnership {
352				toBeAdopted, err = requireAdoption(resources)
353			} else {
354				toBeAdopted, err = existingResourceConflict(resources, rel.Name, rel.Namespace)
355			}
356			if err != nil {
357				return nil, errors.Wrap(err, "Unable to continue with install")
358			}
359		}
360	
361		// Bail out here if it is a dry run
362		if i.isDryRun() {
363			rel.Info.Description = "Dry run complete"
364			return rel, nil
365		}
366	
367		if i.CreateNamespace {
368			ns := &v1.Namespace{
369				TypeMeta: metav1.TypeMeta{
370					APIVersion: "v1",
371					Kind:       "Namespace",
372				},
373				ObjectMeta: metav1.ObjectMeta{
374					Name: i.Namespace,
375					Labels: map[string]string{
376						"name": i.Namespace,
377					},
378				},
379			}
380			buf, err := yaml.Marshal(ns)
381			if err != nil {
382				return nil, err
383			}
384			resourceList, err := i.cfg.KubeClient.Build(bytes.NewBuffer(buf), true)
385			if err != nil {
386				return nil, err
387			}
388			if _, err := i.cfg.KubeClient.Create(resourceList); err != nil && !apierrors.IsAlreadyExists(err) {
389				return nil, err
390			}
391		}
392	
393		// If Replace is true, we need to supersede the last release.
394		if i.Replace {
395			if err := i.replaceRelease(rel); err != nil {
396				return nil, err
397			}
398		}
399	
400		// Store the release in history before continuing (new in Helm 3). We always know
401		// that this is a create operation.
402		if err := i.cfg.Releases.Create(rel); err != nil {
403			// We could try to recover gracefully here, but since nothing has been installed
404			// yet, this is probably safer than trying to continue when we know storage is
405			// not working.
406			return rel, err
407		}
408	
409		rel, err = i.performInstallCtx(ctx, rel, toBeAdopted, resources)
410		if err != nil {
411			rel, err = i.failRelease(rel, err)
412		}
413		return rel, err
414	}
415	
416	func (i *Install) performInstallCtx(ctx context.Context, rel *release.Release, toBeAdopted kube.ResourceList, resources kube.ResourceList) (*release.Release, error) {
417		type Msg struct {
418			r *release.Release
419			e error
420		}
421		resultChan := make(chan Msg, 1)
422	
423		go func() {
424			rel, err := i.performInstall(rel, toBeAdopted, resources)
425			resultChan <- Msg{rel, err}
426		}()
427		select {
428		case <-ctx.Done():
429			err := ctx.Err()
430			return rel, err
431		case msg := <-resultChan:
432			return msg.r, msg.e
433		}
434	}
