436	// isDryRun returns true if Upgrade is set to run as a DryRun
437	func (i *Install) isDryRun() bool {
438		if i.DryRun || i.DryRunOption == "client" || i.DryRunOption == "server" || i.DryRunOption == "true" {
439			return true
440		}
441		return false
442	}
