444	func (i *Install) performInstall(rel *release.Release, toBeAdopted kube.ResourceList, resources kube.ResourceList) (*release.Release, error) {
445		var err error
446		// pre-install hooks
447		if !i.DisableHooks {
448			if err := i.cfg.execHook(rel, release.HookPreInstall, i.Timeout); err != nil {
449				return rel, fmt.Errorf("failed pre-install: %s", err)
450			}
451		}
452	
453		// At this point, we can do the install. Note that before we were detecting whether to
454		// do an update, but it's not clear whether we WANT to do an update if the re-use is set
455		// to true, since that is basically an upgrade operation.
456		if len(toBeAdopted) == 0 && len(resources) > 0 {
457			_, err = i.cfg.KubeClient.Create(resources)
458		} else if len(resources) > 0 {
459			if i.TakeOwnership {
460				_, err = i.cfg.KubeClient.(kube.InterfaceThreeWayMerge).UpdateThreeWayMerge(toBeAdopted, resources, i.Force)
461			} else {
462				_, err = i.cfg.KubeClient.Update(toBeAdopted, resources, i.Force)
463			}
464		}
465		if err != nil {
466			return rel, err
467		}
468	
469		if i.Wait {
470			if i.WaitForJobs {
471				err = i.cfg.KubeClient.WaitWithJobs(resources, i.Timeout)
472			} else {
473				err = i.cfg.KubeClient.Wait(resources, i.Timeout)
474			}
475			if err != nil {
476				return rel, err
477			}
478		}
479	
480		if !i.DisableHooks {
481			if err := i.cfg.execHook(rel, release.HookPostInstall, i.Timeout); err != nil {
482				return rel, fmt.Errorf("failed post-install: %s", err)
483			}
484		}
485	
486		if len(i.Description) > 0 {
487			rel.SetStatus(release.StatusDeployed, i.Description)
488		} else {
489			rel.SetStatus(release.StatusDeployed, "Install complete")
490		}
491	
492		// This is a tricky case. The release has been created, but the result
493		// cannot be recorded. The truest thing to tell the user is that the
494		// release was created. However, the user will not be able to do anything
495		// further with this release.
496		//
497		// One possible strategy would be to do a timed retry to see if we can get
498		// this stored in the future.
499		if err := i.recordRelease(rel); err != nil {
500			i.cfg.Log("failed to record the release: %s", err)
501		}
502	
503		return rel, nil
504	}
505	
506	func (i *Install) failRelease(rel *release.Release, err error) (*release.Release, error) {
507		rel.SetStatus(release.StatusFailed, fmt.Sprintf("Release %q failed: %s", i.ReleaseName, err.Error()))
508		if i.Atomic {
509			i.cfg.Log("Install failed and atomic is set, uninstalling release")
510			uninstall := NewUninstall(i.cfg)
511			uninstall.DisableHooks = i.DisableHooks
512			uninstall.KeepHistory = false
513			uninstall.Timeout = i.Timeout
514			if _, uninstallErr := uninstall.Run(i.ReleaseName); uninstallErr != nil {
515				return rel, errors.Wrapf(uninstallErr, "an error occurred while uninstalling the release. original install error: %s", err)
516			}
517			return rel, errors.Wrapf(err, "release %s failed, and has been uninstalled due to atomic being set", i.ReleaseName)
518		}
519		i.recordRelease(rel) // Ignore the error, since we have another error to deal with.
520		return rel, err
521	}
