523	// availableName tests whether a name is available
524	//
525	// Roughly, this will return an error if name is
526	//
527	//   - empty
528	//   - too long
529	//   - already in use, and not deleted
530	//   - used by a deleted release, and i.Replace is false
531	func (i *Install) availableName() error {
532		start := i.ReleaseName
533	
534		if err := chartutil.ValidateReleaseName(start); err != nil {
535			return errors.Wrapf(err, "release name %q", start)
536		}
537		// On dry run, bail here
538		if i.isDryRun() {
539			return nil
540		}
541	
542		h, err := i.cfg.Releases.History(start)
543		if err != nil || len(h) < 1 {
544			return nil
545		}
546		releaseutil.Reverse(h, releaseutil.SortByRevision)
547		rel := h[0]
548	
549		if st := rel.Info.Status; i.Replace && (st == release.StatusUninstalled || st == release.StatusFailed) {
550			return nil
551		}
552		return errors.New("cannot re-use a name that is still in use")
553	}
