580	// replaceRelease replaces an older release with this one
581	//
582	// This allows us to re-use names by superseding an existing release with a new one
583	func (i *Install) replaceRelease(rel *release.Release) error {
584		hist, err := i.cfg.Releases.History(rel.Name)
585		if err != nil || len(hist) == 0 {
586			// No releases exist for this name, so we can return early
587			return nil
588		}
589	
590		releaseutil.Reverse(hist, releaseutil.SortByRevision)
591		last := hist[0]
592	
593		// Update version to the next available
594		rel.Version = last.Version + 1
595	
596		// Do not change the status of a failed release.
597		if last.Info.Status == release.StatusFailed {
598			return nil
599		}
600	
601		// For any other status, mark it as superseded and store the old record
602		last.SetStatus(release.StatusSuperseded, "superseded by new release")
603		return i.recordRelease(last)
604	}
