606	// write the <data> to <output-dir>/<name>. <append> controls if the file is created or content will be appended
607	func writeToFile(outputDir string, name string, data string, append bool) error {
608		outfileName := strings.Join([]string{outputDir, name}, string(filepath.Separator))
609	
610		err := ensureDirectoryForFile(outfileName)
611		if err != nil {
612			return err
613		}
614	
615		f, err := createOrOpenFile(outfileName, append)
616		if err != nil {
617			return err
618		}
619	
620		defer f.Close()
621	
622		_, err = f.WriteString(fmt.Sprintf("---\n# Source: %s\n%s\n", name, data))
623	
624		if err != nil {
625			return err
626		}
627	
628		fmt.Printf("wrote %s\n", outfileName)
629		return nil
630	}
631	
632	func createOrOpenFile(filename string, append bool) (*os.File, error) {
633		if append {
634			return os.OpenFile(filename, os.O_APPEND|os.O_WRONLY, 0600)
635		}
636		return os.Create(filename)
637	}
638	
639	// check if the directory exists to create file. creates if doesn't exist
640	func ensureDirectoryForFile(file string) error {
641		baseDir := path.Dir(file)
642		_, err := os.Stat(baseDir)
643		if err != nil && !os.IsNotExist(err) {
644			return err
645		}
646	
647		return os.MkdirAll(baseDir, defaultDirectoryPermission)
648	}
