650	// NameAndChart returns the name and chart that should be used.
651	//
652	// This will read the flags and handle name generation if necessary.
653	func (i *Install) NameAndChart(args []string) (string, string, error) {
654		flagsNotSet := func() error {
655			if i.GenerateName {
656				return errors.New("cannot set --generate-name and also specify a name")
657			}
658			if i.NameTemplate != "" {
659				return errors.New("cannot set --name-template and also specify a name")
660			}
661			return nil
662		}
663	
664		if len(args) > 2 {
665			return args[0], args[1], errors.Errorf("expected at most two arguments, unexpected arguments: %v", strings.Join(args[2:], ", "))
666		}
667	
668		if len(args) == 2 {
669			return args[0], args[1], flagsNotSet()
670		}
671	
672		if i.NameTemplate != "" {
673			name, err := TemplateName(i.NameTemplate)
674			return name, args[0], err
675		}
676	
677		if i.ReleaseName != "" {
678			return i.ReleaseName, args[0], nil
679		}
680	
681		if !i.GenerateName {
682			return "", args[0], errors.New("must either provide a name or specify --generate-name")
683		}
684	
685		base := filepath.Base(args[0])
686		if base == "." || base == "" {
687			base = "chart"
688		}
689		// if present, strip out the file extension from the name
690		if idx := strings.Index(base, "."); idx != -1 {
691			base = base[0:idx]
692		}
693	
694		return fmt.Sprintf("%s-%d", base, time.Now().Unix()), args[0], nil
695	}
