697	// TemplateName renders a name template, returning the name or an error.
698	func TemplateName(nameTemplate string) (string, error) {
699		if nameTemplate == "" {
700			return "", nil
701		}
702	
703		t, err := template.New("name-template").Funcs(sprig.TxtFuncMap()).Parse(nameTemplate)
704		if err != nil {
705			return "", err
706		}
707		var b bytes.Buffer
708		if err := t.Execute(&b, nil); err != nil {
709			return "", err
710		}
711	
712		return b.String(), nil
713	}
