715	// CheckDependencies checks the dependencies for a chart.
716	func CheckDependencies(ch *chart.Chart, reqs []*chart.Dependency) error {
717		var missing []string
718	
719	OUTER:
720		for _, r := range reqs {
721			for _, d := range ch.Dependencies() {
722				if d.Name() == r.Name {
723					continue OUTER
724				}
725			}
726			missing = append(missing, r.Name)
727		}
728	
729		if len(missing) > 0 {
730			return errors.Errorf("found in Chart.yaml, but missing in charts/ directory: %s", strings.Join(missing, ", "))
731		}
732		return nil
733	}
