735	// LocateChart looks for a chart directory in known places, and returns either the full path or an error.
736	//
737	// This does not ensure that the chart is well-formed; only that the requested filename exists.
738	//
739	// Order of resolution:
740	// - relative to current working directory
741	// - if path is absolute or begins with '.', error out here
742	// - URL
743	//
744	// If 'verify' was set on ChartPathOptions, this will attempt to also verify the chart.
745	func (c *ChartPathOptions) LocateChart(name string, settings *cli.EnvSettings) (string, error) {
746		if registry.IsOCI(name) && c.registryClient == nil {
747			return "", fmt.Errorf("unable to lookup chart %q, missing registry client", name)
748		}
749	
750		name = strings.TrimSpace(name)
751		version := strings.TrimSpace(c.Version)
752	
753		if _, err := os.Stat(name); err == nil {
754			// Issue #7862: Helm prioritizes local charts over repository URL.
755			// This behavior is maintained for backwards compatibility but with a warning.
756			if c.RepoURL != "" {
757				slog.Warn("local chart found in current working directory. repository url ignored", "chart", name, "repository", c.RepoURL)
758			}
759	
760			abs, err := filepath.Abs(name)
761			if err != nil {
762				return abs, err
763			}
764			if c.Verify {
765				if _, err := downloader.VerifyChart(abs, c.Keyring); err != nil {
766					return "", err
767				}
768			}
769			return abs, nil
770		}
771		if filepath.IsAbs(name) || strings.HasPrefix(name, ".") {
772			return name, errors.Errorf("path %q not found", name)
773		}
774	
775		dl := downloader.ChartDownloader{
776			Out:     os.Stdout,
777			Keyring: c.Keyring,
778			Getters: getter.All(settings),
779			Options: []getter.Option{
780				getter.WithPassCredentialsAll(c.PassCredentialsAll),
781				getter.WithTLSClientConfig(c.CertFile, c.KeyFile, c.CaFile),
782				getter.WithInsecureSkipVerifyTLS(c.InsecureSkipTLSverify),
783				getter.WithPlainHTTP(c.PlainHTTP),
784				getter.WithBasicAuth(c.Username, c.Password),
785			},
786			RepositoryConfig: settings.RepositoryConfig,
787			RepositoryCache:  settings.RepositoryCache,
788			RegistryClient:   c.registryClient,
789		}
790	
791		if registry.IsOCI(name) {
792			dl.Options = append(dl.Options, getter.WithRegistryClient(c.registryClient))
793		}
794	
795		if c.Verify {
796			dl.Verify = downloader.VerifyAlways
797		}
798		if c.RepoURL != "" {
799			chartURL, err := repo.FindChartInAuthAndTLSAndPassRepoURL(c.RepoURL, c.Username, c.Password, name, version,
800				c.CertFile, c.KeyFile, c.CaFile, c.InsecureSkipTLSverify, c.PassCredentialsAll, getter.All(settings))
801			if err != nil {
802				return "", err
803			}
804			name = chartURL
805	
806			// Only pass the user/pass on when the user has said to or when the
807			// location of the chart repo and the chart are the same domain.
808			u1, err := url.Parse(c.RepoURL)
809			if err != nil {
810				return "", err
811			}
812			u2, err := url.Parse(chartURL)
813			if err != nil {
814				return "", err
815			}
816	
817			// Host on URL (returned from url.Parse) contains the port if present.
818			// This check ensures credentials are not passed between different
819			// services on different ports.
820			if c.PassCredentialsAll || (u1.Scheme == u2.Scheme && u1.Host == u2.Host) {
821				dl.Options = append(dl.Options, getter.WithBasicAuth(c.Username, c.Password))
822			} else {
823				dl.Options = append(dl.Options, getter.WithBasicAuth("", ""))
824			}
825		} else {
826			dl.Options = append(dl.Options, getter.WithBasicAuth(c.Username, c.Password))
827		}
828	
829		if err := os.MkdirAll(settings.RepositoryCache, 0755); err != nil {
830			return "", err
831		}
832	
833		filename, _, err := dl.DownloadTo(name, version, settings.RepositoryCache)
834		if err != nil {
835			return "", err
836		}
837	
838		lname, err := filepath.Abs(filename)
839		if err != nil {
840			return filename, err
841		}
842		return lname, nil
843	}
