25	// ListReleases lists all releases.
26	func (c *HelmClient) ListReleases(namespaces []string, selector string) ([]*release.Release, error) {
27		releases := []*release.Release{}
28		for _, ns := range namespaces {
29			hc, err := c.HelmConfig(ns)
30			if err != nil {
31				return nil, fmt.Errorf("failed to get helm config for namespace %s: %w", ns, err)
32			}
33			listClient := action.NewList(hc)
34			listClient.All = true
35			listClient.Limit = 0
36			listClient.Selector = selector
37			listClient.SetStateMask()
38			nsReleases, err := listClient.Run()
39			if err != nil {
40				return nil, fmt.Errorf("failed to list releases in namespace %s: %w", ns, err)
41			}
42			releases = append(releases, nsReleases...)
43		}
44		if len(namespaces) == 0 {
45			hc, err := c.HelmConfig("")
46			listClient := action.NewList(hc)
47			listClient.All = true
48			listClient.AllNamespaces = true
49			listClient.Limit = 0
50			listClient.Selector = selector
51			listClient.SetStateMask()
52			releases, err = listClient.Run()
53			if err != nil {
54				return nil, fmt.Errorf("failed to list releases in all namespaces: %w", err)
55			}
56		}
57		return releases, nil
58	}
