268	func (c *HelmClient) Rollback(rollbackReleaseRequest models.RollbackReleaseRequest) error {
269		namespace := rollbackReleaseRequest.Namespace
270		name := rollbackReleaseRequest.Name
271		toRevision := rollbackReleaseRequest.ToRevision
272		host, username, password := rollbackReleaseRequest.HelmRepository.Host, rollbackReleaseRequest.HelmRepository.UserName, rollbackReleaseRequest.HelmRepository.Password
273	
274		origRelease, err := c.GetReleasesByName(namespace, name)
275		if err != nil {
276			return fmt.Errorf("failed to get release %s in namespace %s: %w", name, namespace, err)
277		}
278	
279		hc, err := c.HelmConfig(namespace)
280		if err != nil {
281			return fmt.Errorf("failed to get helm config for namespace %s: %w", namespace, err)
282		}
283	
284		registryClient, err := c.GetRegistryClient(host, username, password)
285		if err != nil {
286			return fmt.Errorf("failed to get registry client: %w", err)
287		}
288		hc.RegistryClient = registryClient
289	
290		rollbackClient := action.NewRollback(hc)
291		rollbackClient.Recreate = true
292		rollbackClient.Version = toRevision
293		err = rollbackClient.Run(name)
294		if err != nil {
295			return fmt.Errorf("failed to rollback the release: %w", err)
296		}
297		log.Infof("Rolled back %s/%s to %d=>%d", namespace, name, origRelease.Version, toRevision)
298		return nil
299	}
