361	func (c *HelmClient) GetRegistryClient(host, username, password string) (*registry.Client, error) {
362		if cli, ok := c.RegistryClients[host]; ok {
363			return cli, nil
364		}
365	
366		opts := []registry.ClientOption{
367			registry.ClientOptEnableCache(true),
368			registry.ClientOptWriter(os.Stderr),
369			registry.ClientOptCredentialsFile(c.Settings.RegistryConfig),
370			registry.ClientOptPlainHTTP(),
371		}
372		registryClient, err := registry.NewClient(opts...)
373		if err != nil {
374			return nil, err
375		}
376		password, err = util.DecryptWithPrivateKey(password)
377		if err != nil {
378			return nil, fmt.Errorf("failed to decrypt registry password: %w", err)
379		}
380		err = registryClient.Login(host, registry.LoginOptBasicAuth(username, password), registry.LoginOptInsecure(true), registry.LoginOptPlainText(true))
381		if err != nil {
382			return nil, err
383		}
384		c.RegistryClients[host] = registryClient
385		return registryClient, nil
386	}
